      "path": "src/modules/tasks/service.js",
      "content": "const { generateId } = require('../../lib/id');
let projectsStore = {};

const createTask = (projectId) => {
  if (!projectsStore[projectId]) {
    projectsStore[projectId] = { tasks: [] };
  }
  const task = { id: generateId(), status: 'todo' };
  projectsStore[projectId].tasks.push(task);
  return task;
};

const getTasksByProject = (projectId) => {
  return projectsStore[projectId]?.tasks || [];
};

const updateTask = (projectId, taskId, status) => {
  const tasks = projectsStore[projectId]?.tasks;
  if (!tasks) return null;

  const taskIndex = tasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) return null;

  tasks[taskIndex].status = status;
  return tasks[taskIndex];
};

module.exports = { createTask, getTasksByProject, updateTask };
